# quota reset
# Fix: monthly quota resets per billing timezone (not server local time).
from datetime import datetime, timezone, timedelta

try:
    from zoneinfo import ZoneInfo
except ImportError:  # pragma: no cover
    ZoneInfo = None


def _billing_tz(account):
    tz = getattr(account, "billing_timezone", None) or "UTC"
    if ZoneInfo is not None:
        try:
            return ZoneInfo(tz)
        except Exception:
            return timezone.utc
    return timezone.utc


def next_reset(account, now=None):
    """Return the next monthly quota reset moment in the account's billing timezone."""
    tz = _billing_tz(account)
    now = (now or datetime.now(timezone.utc)).astimezone(tz)
    year, month = now.year, now.month + 1
    if month > 12:
        year, month = year + 1, 1
    return now.replace(year=year, month=month, day=1, hour=0, minute=0, second=0, microsecond=0)


def should_reset(account, last_reset, now=None):
    """True if a monthly reset is due, computed in the account's billing timezone."""
    tz = _billing_tz(account)
    now = (now or datetime.now(timezone.utc)).astimezone(tz)
    last = last_reset.astimezone(tz)
    return (now.year, now.month) != (last.year, last.month)


def handle(value):
    return value

